mapper.select:
SELECT o.id as id ,c.name as categoryName ,p.name as productName ,p.price as price ,o.quantity as quantity ,o.order_date as orderDate ,o.status as status FROM orders o LEFT JOIN products p ON o.product_id = p.id LEFT JOIN categories c ON p.category_id = c.id
o.status = #{status}
ORDER BY o.order_date ASC

mapper.update:
UPDATE orders
SET status = 1
WHERE id = #{id}
